import { getScenario, scenarios } from "./scenarios/index";
import type { ReplayTarget } from "./types";

interface CliOptions {
  baseUrl?: string;
  json: boolean;
  target?: ReplayTarget;
  timeoutMs?: number;
}

function printUsage(): void {
  console.log(`Usage:
  pnpm --filter @repo/app-test-data sandbox:list
  pnpm --filter @repo/app-test-data sandbox:doctor
  pnpm --filter @repo/app-test-data sandbox:seed -- <scenario>
  pnpm --filter @repo/app-test-data sandbox:replay -- <scenario> [--target platform|app] [--base-url URL]
  pnpm --filter @repo/app-test-data sandbox:run -- <scenario> [--target platform|app] [--base-url URL] [--timeout-ms NUMBER]

Options:
  --json                  Print JSON output
  --target                Replay target: platform or app
  --base-url              Override the selected target base URL
  --timeout-ms            Assertion timeout used by run
`);
}

function parseArgs(argv: string[]): {
  command: string | undefined;
  options: CliOptions;
  scenarioName?: string;
} {
  const [command, ...rest] = argv;
  const options: CliOptions = { json: false };
  let scenarioName: string | undefined;

  for (let index = 0; index < rest.length; index += 1) {
    const current = rest[index];
    if (!current) {
      continue;
    }

    if (current === "--") {
      continue;
    }

    if (current === "--json") {
      options.json = true;
      continue;
    }

    if (current === "--target") {
      const value = rest[index + 1];
      if (value === "app" || value === "platform") {
        options.target = value;
        index += 1;
        continue;
      }
      throw new Error(`Invalid --target value "${value ?? ""}"`);
    }

    if (current === "--base-url") {
      const value = rest[index + 1];
      if (!value) {
        throw new Error("Missing value for --base-url");
      }
      options.baseUrl = value;
      index += 1;
      continue;
    }

    if (current === "--timeout-ms") {
      const value = rest[index + 1];
      if (!value) {
        throw new Error("Missing value for --timeout-ms");
      }
      const parsed = Number.parseInt(value, 10);
      if (!Number.isFinite(parsed)) {
        throw new Error(`Invalid --timeout-ms value "${value}"`);
      }
      options.timeoutMs = parsed;
      index += 1;
      continue;
    }

    if (current.startsWith("--")) {
      throw new Error(`Unknown option "${current}"`);
    }

    scenarioName ??= current;
  }

  return { command, scenarioName, options };
}

function printOutput(value: unknown, json: boolean): void {
  if (json) {
    console.log(JSON.stringify(value, null, 2));
    return;
  }

  console.dir(value, { depth: null, colors: true });
}

async function main(): Promise<void> {
  const { command, scenarioName, options } = parseArgs(process.argv.slice(2));

  switch (command) {
    case "list":
      printOutput(
        scenarios.map((scenario) => ({
          name: scenario.name,
          description: scenario.description,
        })),
        options.json
      );
      return;

    case "doctor":
      printOutput(await (await import("./doctor")).doctor(), options.json);
      return;

    case "seed": {
      if (!scenarioName) {
        throw new Error("Missing scenario name for seed");
      }
      const scenario = getScenario(scenarioName);
      printOutput(
        await (await import("./seed")).seedScenario(scenario),
        options.json
      );
      return;
    }

    case "replay": {
      if (!scenarioName) {
        throw new Error("Missing scenario name for replay");
      }
      const scenario = getScenario(scenarioName);
      printOutput(
        await (await import("./replay")).replayScenario(scenario, {
          target: options.target,
          baseUrl: options.baseUrl,
        }),
        options.json
      );
      return;
    }

    case "run": {
      if (!scenarioName) {
        throw new Error("Missing scenario name for run");
      }
      const scenario = getScenario(scenarioName);
      printOutput(
        await (await import("./run")).runScenario(
          scenario,
          {
            target: options.target,
            baseUrl: options.baseUrl,
          },
          {
            timeoutMs: options.timeoutMs,
          }
        ),
        options.json
      );
      return;
    }

    case undefined:
      printUsage();
      return;

    default:
      throw new Error(`Unknown command "${command}"`);
  }
}

main().catch((error) => {
  const message = error instanceof Error ? error.message : String(error);
  console.error(message);
  printUsage();
  process.exit(1);
});

