1	import { readFileSync } from "node:fs";
2	import { basename, join } from "node:path";
3	import type { ProviderSlug } from "@repo/app-providers";
4	import { getProvider } from "../../../app-providers/src/registry";
5	import type { LoadedFixture } from "../types";
6	
7	const FIXTURES_DIR = join(import.meta.dirname, "../../../webhook-schemas/fixtures");
8	
9	function assertProvider(slug: string): ProviderSlug {
10	  const provider = getProvider(slug);
11	  if (!provider) {
12	    throw new Error(`Unknown provider "${slug}" in fixture reference`);
13	  }
14	  return slug as ProviderSlug;
15	}
16	
17	export function resolveFixturePath(fixtureRef: string): string {
18	  return join(FIXTURES_DIR, fixtureRef);
19	}
20	
21	export function loadFixture(fixtureRef: string): LoadedFixture {
22	  const [providerPart] = fixtureRef.split("/", 1);
23	  if (!providerPart) {
24	    throw new Error(`Invalid fixture reference "${fixtureRef}"`);
25	  }
26	
27	  const provider = assertProvider(providerPart);
28	  const fixturePath = resolveFixturePath(fixtureRef);
29	  const raw = readFileSync(fixturePath, "utf8");
30	  const payload = JSON.parse(raw) as Record<string, unknown>;
31	
32	  return {
33	    provider,
34	    fixtureRef,
35	    fixturePath,
36	    payload,
37	    eventKey: basename(fixtureRef, ".json"),
38	  };
39	}
40	
41	export function deriveResourceIdFromFixture(fixture: LoadedFixture): string {
42	  const provider = getProvider(fixture.provider);
43	  if (!provider || provider.kind !== "webhook") {
44	    throw new Error(
45	      `Provider "${fixture.provider}" does not expose a webhook resource extractor`
46	    );
47	  }
48	
49	  const resourceId = provider.webhook.extractResourceId(fixture.payload);
50	  if (!resourceId) {
51	    throw new Error(
52	      `Fixture "${fixture.fixtureRef}" did not resolve a provider resource ID`
53	    );
54	  }
55	
56	  return resourceId;
57	}
58	
59	export function deriveInboundEventType(fixture: LoadedFixture): string {
60	  switch (fixture.provider) {
61	    case "github":
62	      return fixture.eventKey.split(".")[0] ?? fixture.eventKey;
63	    case "linear": {
64	      const type = fixture.payload.type;
65	      return typeof type === "string"
66	        ? type
67	        : (fixture.eventKey.split(".")[0] ?? fixture.eventKey);
68	    }
69	    case "sentry":
70	      return fixture.eventKey;
71	    case "vercel": {
72	      const type = fixture.payload.type;
73	      return typeof type === "string" ? type : fixture.eventKey;
74	    }
75	    default:
76	      return fixture.eventKey;
77	  }
78	}
79	
80	export function overrideFixtureResourceId(
81	  fixture: LoadedFixture,
82	  resourceId: string
83	): LoadedFixture {
84	  const payload = structuredClone(fixture.payload) as Record<string, unknown>;
85	
86	  switch (fixture.provider) {
87	    case "github": {
88	      const repository = payload.repository;
89	      if (!repository || typeof repository !== "object") {
90	        throw new Error(
91	          `Fixture "${fixture.fixtureRef}" is missing payload.repository for override`
92	        );
93	      }
94	      const numericId = Number.parseInt(resourceId, 10);
95	      if (!Number.isFinite(numericId)) {
96	        throw new Error(
97	          `GitHub resource override "${resourceId}" must be a numeric repository ID`
98	        );
99	      }
100	      (repository as { id: number }).id = numericId;
101	      break;
102	    }
103	
104	    case "linear":
105	      payload.organizationId = resourceId;
106	      break;
107	
108	    case "sentry": {
109	      const installation = payload.installation;
110	      if (!installation || typeof installation !== "object") {
111	        throw new Error(
112	          `Fixture "${fixture.fixtureRef}" is missing payload.installation for override`
113	        );
114	      }
115	      (installation as { uuid: string }).uuid = resourceId;
116	      break;
117	    }
118	
119	    case "vercel": {
120	      const innerPayload = payload.payload;
121	      if (
122	        !innerPayload ||
123	        typeof innerPayload !== "object" ||
124	        !("project" in innerPayload)
125	      ) {
126	        throw new Error(
127	          `Fixture "${fixture.fixtureRef}" is missing payload.project for override`
128	        );
129	      }
130	      const project = (innerPayload as { project?: Record<string, unknown> })
131	        .project;
132	      if (!project || typeof project !== "object") {
133	        throw new Error(
