import { readFileSync } from "node:fs";
import { basename, join } from "node:path";
import type { ProviderSlug } from "@repo/app-providers";
import { getProvider } from "../../../app-providers/src/registry";
import type { LoadedFixture } from "../types";

const FIXTURES_DIR = join(import.meta.dirname, "../../../webhook-schemas/fixtures");

function assertProvider(slug: string): ProviderSlug {
  const provider = getProvider(slug);
  if (!provider) {
    throw new Error(`Unknown provider "${slug}" in fixture reference`);
  }
  return slug as ProviderSlug;
}

export function resolveFixturePath(fixtureRef: string): string {
  return join(FIXTURES_DIR, fixtureRef);
}

export function loadFixture(fixtureRef: string): LoadedFixture {
  const [providerPart] = fixtureRef.split("/", 1);
  if (!providerPart) {
    throw new Error(`Invalid fixture reference "${fixtureRef}"`);
  }

  const provider = assertProvider(providerPart);
  const fixturePath = resolveFixturePath(fixtureRef);
  const raw = readFileSync(fixturePath, "utf8");
  const payload = JSON.parse(raw) as Record<string, unknown>;

  return {
    provider,
    fixtureRef,
    fixturePath,
    payload,
    eventKey: basename(fixtureRef, ".json"),
  };
}

export function deriveResourceIdFromFixture(fixture: LoadedFixture): string {
  const provider = getProvider(fixture.provider);
  if (!provider || provider.kind !== "webhook") {
    throw new Error(
      `Provider "${fixture.provider}" does not expose a webhook resource extractor`
    );
  }

  const resourceId = provider.webhook.extractResourceId(fixture.payload);
  if (!resourceId) {
    throw new Error(
      `Fixture "${fixture.fixtureRef}" did not resolve a provider resource ID`
    );
  }

  return resourceId;
}

export function deriveInboundEventType(fixture: LoadedFixture): string {
  switch (fixture.provider) {
    case "github":
      return fixture.eventKey.split(".")[0] ?? fixture.eventKey;
    case "linear": {
      const type = fixture.payload.type;
      return typeof type === "string"
        ? type
        : (fixture.eventKey.split(".")[0] ?? fixture.eventKey);
    }
    case "sentry":
      return fixture.eventKey;
    case "vercel": {
      const type = fixture.payload.type;
      return typeof type === "string" ? type : fixture.eventKey;
    }
    default:
      return fixture.eventKey;
  }
}

export function overrideFixtureResourceId(
  fixture: LoadedFixture,
  resourceId: string
): LoadedFixture {
  const payload = structuredClone(fixture.payload) as Record<string, unknown>;

  switch (fixture.provider) {
    case "github": {
      const repository = payload.repository;
      if (!repository || typeof repository !== "object") {
        throw new Error(
          `Fixture "${fixture.fixtureRef}" is missing payload.repository for override`
        );
      }
      const numericId = Number.parseInt(resourceId, 10);
      if (!Number.isFinite(numericId)) {
        throw new Error(
          `GitHub resource override "${resourceId}" must be a numeric repository ID`
        );
      }
      (repository as { id: number }).id = numericId;
      break;
    }

    case "linear":
      payload.organizationId = resourceId;
      break;

    case "sentry": {
      const installation = payload.installation;
      if (!installation || typeof installation !== "object") {
        throw new Error(
          `Fixture "${fixture.fixtureRef}" is missing payload.installation for override`
        );
      }
      (installation as { uuid: string }).uuid = resourceId;
      break;
    }

    case "vercel": {
      const innerPayload = payload.payload;
      if (
        !innerPayload ||
        typeof innerPayload !== "object" ||
        !("project" in innerPayload)
      ) {
        throw new Error(
          `Fixture "${fixture.fixtureRef}" is missing payload.project for override`
        );
      }
      const project = (innerPayload as { project?: Record<string, unknown> })
        .project;
      if (!project || typeof project !== "object") {
        throw new Error(
          `Fixture "${fixture.fixtureRef}" is missing payload.project for override`
        );
      }
      project.id = resourceId;
      break;
    }
  }

  return {
    ...fixture,
    payload,
  };
}

