import { createHmac, randomUUID } from "node:crypto";
import type { LoadedFixture, ReplayRequest } from "../types";
import { deriveInboundEventType } from "./fixtures";

function requireEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing required env var ${name} for local replay signing`);
  }
  return value;
}

function sign(algorithm: "sha1" | "sha256", secret: string, body: string): string {
  return createHmac(algorithm, secret).update(body).digest("hex");
}

export function buildReplayRequest(fixture: LoadedFixture): ReplayRequest {
  const body = JSON.stringify(fixture.payload);
  const inboundEventType = deriveInboundEventType(fixture);

  switch (fixture.provider) {
    case "github": {
      const deliveryId = `lf-e2e-${randomUUID()}`;
      const signature = sign("sha256", requireEnv("GITHUB_WEBHOOK_SECRET"), body);

      return {
        body,
        deliveryId,
        inboundEventType,
        headers: {
          "content-type": "application/json",
          "x-github-delivery": deliveryId,
          "x-github-event": inboundEventType,
          "x-hub-signature-256": `sha256=${signature}`,
        },
      };
    }

    case "linear": {
      const deliveryId = `lf-e2e-${randomUUID()}`;
      const signature = sign(
        "sha256",
        requireEnv("LINEAR_WEBHOOK_SIGNING_SECRET"),
        body
      );

      return {
        body,
        deliveryId,
        inboundEventType,
        headers: {
          "content-type": "application/json",
          "linear-delivery": deliveryId,
          "linear-signature": signature,
        },
      };
    }

    case "sentry": {
      const timestamp = `${Math.floor(Date.now() / 1000)}`;
      const deliveryId = `${inboundEventType}:${timestamp}`;
      const signature = sign("sha256", requireEnv("SENTRY_CLIENT_SECRET"), body);

      return {
        body,
        deliveryId,
        inboundEventType,
        headers: {
          "content-type": "application/json",
          "sentry-hook-resource": inboundEventType,
          "sentry-hook-signature": signature,
          "sentry-hook-timestamp": timestamp,
        },
      };
    }

    case "vercel": {
      const payloadId = fixture.payload.id;
      const deliveryId =
        typeof payloadId === "string" && payloadId.length > 0
          ? payloadId
          : `lf-e2e-${randomUUID()}`;
      const signature = sign(
        "sha1",
        requireEnv("VERCEL_CLIENT_INTEGRATION_SECRET"),
        body
      );

      return {
        body,
        deliveryId,
        inboundEventType,
        headers: {
          "content-type": "application/json",
          "x-vercel-signature": signature,
        },
      };
    }
  }

  throw new Error(`Unsupported provider "${fixture.provider}" for local replay`);
}

