async function checkUrl(name: string, url: string): Promise<ServiceCheck> {
  try {
    const response = await fetch(url, {
      method: "GET",
      signal: AbortSignal.timeout(3_000),
    });

    return {
      name,
      url,
      status: response.status,
      ok: response.ok,
    };
  } catch {
    return {
      name,
      url,
      status: null,
      ok: false,
    };
  }
}

