  const services = await Promise.all([
    checkUrl("platform health", `${DEFAULT_PLATFORM_BASE_URL}/api/health`),
    checkUrl("platform inngest", `${DEFAULT_PLATFORM_BASE_URL}/api/inngest`),
    checkUrl("app ingress proxy", `${DEFAULT_APP_BASE_URL}/api/inngest`),
  ]);

  const envs: EnvCheck[] = listSandboxProviders().flatMap(([slug, provider]) =>
    provider.requiredEnvVars.map((name) => ({
      name: `${slug} signing secret`,
      var: name,
      present: Boolean(process.env[name]),
    }))
  );

  return { services, envs };
}

