import { resolveBaseUrl } from "./config";
import type {
  LocalE2EScenario,
  ReplayOptions,
  ReplayResult,
  ScenarioReplayStep,
} from "./types";
import { loadFixture, overrideFixtureResourceId } from "./lib/fixtures";
import { buildReplayRequest } from "./lib/signing";

async function parseResponseBody(response: Response): Promise<unknown> {
  const text = await response.text();
  if (!text) {
    return null;
  }

  try {
    return JSON.parse(text) as unknown;
  } catch {
    return text;
  }
}

export async function replayStep(
  step: ScenarioReplayStep,
  options: ReplayOptions = {}
): Promise<ReplayResult> {
  let fixture = loadFixture(step.fixture);
  if (step.resourceIdOverride) {
    fixture = overrideFixtureResourceId(fixture, step.resourceIdOverride);
  }
  const request = buildReplayRequest(fixture);
  const target = step.target ?? options.target ?? "platform";
  const baseUrl = resolveBaseUrl(target, options.baseUrl);
  const url = `${baseUrl}/api/ingest/${fixture.provider}`;

  const response = await fetch(url, {
    method: "POST",
    headers: request.headers,
    body: request.body,
    signal: AbortSignal.timeout(10_000),
  });

  const body = await parseResponseBody(response);
  const acceptedDeliveryId =
    body &&
    typeof body === "object" &&
    "deliveryId" in body &&
    typeof body.deliveryId === "string"
      ? body.deliveryId
      : null;

  return {
    provider: fixture.provider,
    fixtureRef: fixture.fixtureRef,
    eventKey: fixture.eventKey,
    target,
    url,
    deliveryId: request.deliveryId,
    inboundEventType: request.inboundEventType,
    status: response.status,
    body,
    acceptedDeliveryId,
  };
}

export async function replayScenario(
  scenario: LocalE2EScenario,
  options: ReplayOptions = {}
): Promise<ReplayResult[]> {
  const results: ReplayResult[] = [];

  for (const step of scenario.replays) {
    results.push(await replayStep(step, options));
  }

  return results;
}

import { readFileSync } from "node:fs";
import { basename, join } from "node:path";
import type { ProviderSlug } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import type { LoadedFixture } from "../types";
import { getSandboxProvider } from "./providers";

const FIXTURES_DIR = join(import.meta.dirname, "../../../webhook-schemas/fixtures");

function assertProvider(slug: string): ProviderSlug {
  const provider = getProvider(slug);
  if (!provider) {
    throw new Error(`Unknown provider "${slug}" in fixture reference`);
  }
  return slug as ProviderSlug;
}

export function resolveFixturePath(fixtureRef: string): string {
  return join(FIXTURES_DIR, fixtureRef);
}

export function loadFixture(fixtureRef: string): LoadedFixture {
  const [providerPart] = fixtureRef.split("/", 1);
  if (!providerPart) {
    throw new Error(`Invalid fixture reference "${fixtureRef}"`);
  }

  const provider = assertProvider(providerPart);
  const fixturePath = resolveFixturePath(fixtureRef);
  const raw = readFileSync(fixturePath, "utf8");
  const payload = JSON.parse(raw) as Record<string, unknown>;

  return {
    provider,
    fixtureRef,
    fixturePath,
    payload,
    eventKey: basename(fixtureRef, ".json"),
  };
}

export function deriveResourceIdFromFixture(fixture: LoadedFixture): string {
  const provider = getProvider(fixture.provider);
  if (!provider || provider.kind !== "webhook") {
    throw new Error(
      `Provider "${fixture.provider}" does not expose a webhook resource extractor`
    );
  }

  const resourceId = provider.webhook.extractResourceId(fixture.payload);
  if (!resourceId) {
    throw new Error(
      `Fixture "${fixture.fixtureRef}" did not resolve a provider resource ID`
    );
  }

  return resourceId;
}

export function deriveInboundEventType(fixture: LoadedFixture): string {
  return getSandboxProvider(fixture.provider).deriveInboundEventType(fixture);
}

export function overrideFixtureResourceId(
  fixture: LoadedFixture,
  resourceId: string
): LoadedFixture {
  return getSandboxProvider(fixture.provider).overrideResourceId(
    fixture,
    resourceId
  );
}

